//  REG/WIRE declarations
//=======================================================
reg [CLK_DIV-1 : 0] CLK_DIV_reg = {CLK_DIV{1'b0}};
reg [7:0] led_counter = 8'h00;
// for detect rising
reg clk_1hz_d;

wire clk_1hz =  CLK_DIV_reg[CLK_DIV-1];
wire tick_1hz = clk_1hz & ~clk_1hz_d;

//=======================================================
//  Structural coding
//=======================================================
assign LED = led_counter;

