	CLK_DIV_reg <= CLK_DIV_reg + 1'b1;
end

always @ (posedge CLOCK_50) begin
	clk_1hz_d <= clk_1hz;
end

always @ (posedge CLOCK_50) begin
	if (tick_1hz) begin
		led_counter <= led_counter + 1'b1;
	end
end

